using System.Text.Json;
using System.Text.Json.Serialization;
using System.Text.Json.Serialization.Metadata;

// Use a source-generated context so the resolver only knows specific types.
var options = new JsonSerializerOptions { TypeInfoResolver = MyContext.Default };

// ── 1. Strongly-typed retrieval: GetTypeInfo<T>() ──────────────────────
//    Returns JsonTypeInfo<T> directly — no manual cast needed.
JsonTypeInfo<string> stringInfo = options.GetTypeInfo<string>();
Console.WriteLine($"Got typed metadata  : {stringInfo.Type.Name}  (JsonTypeInfo<{stringInfo.Type.Name}>)");

string json = JsonSerializer.Serialize("hello", stringInfo);
Console.WriteLine($"Serialized with it  : {json}");

// ── 2. Probe without throwing: TryGetTypeInfo() ────────────────────────
if (options.TryGetTypeInfo(typeof(int), out JsonTypeInfo? intInfo))
    Console.WriteLine($"\nint metadata found  : {intInfo!.Type.Name}");

// TimeZoneInfo is NOT in the source-gen context → should return false.
if (options.TryGetTypeInfo(typeof(TimeZoneInfo), out JsonTypeInfo? tzInfo))
    Console.WriteLine($"\nTimeZoneInfo found  : {tzInfo!.Type.Name}");
else
    Console.WriteLine($"\nTimeZoneInfo metadata not available — no exception thrown.");

// Source-gen context that only knows about string and int.
[JsonSerializable(typeof(string))]
[JsonSerializable(typeof(int))]
partial class MyContext : JsonSerializerContext { }

